import time
from concurrent.futures import ThreadPoolExecutor, as_completed

def fan_out_chunked(
    documents: list[dict],
    max_workers: int = 4,
    chunk_size: int = 8,
    delay_between_chunks: float = 0.5,
) -> list[dict]:
    """
    Fan-out with chunked batching.
    Runs at most chunk_size tasks per batch; waits delay_between_chunks seconds between batches.
    Limits API rate without blocking on a single slow request.
    """
    all_results = []
    for batch_start in range(0, len(documents), chunk_size):
        batch = documents[batch_start: batch_start + chunk_size]

        with ThreadPoolExecutor(max_workers=min(max_workers, len(batch))) as pool:
            futures = {
                pool.submit(summarize_document, doc["text"], doc["id"]): doc["id"]
                for doc in batch
            }
            for future in as_completed(futures):
                doc_id = futures[future]
                try:
                    all_results.append(future.result())
                except Exception as e:
                    all_results.append({"doc_id": doc_id, "summary": None, "error": str(e)})

        # Brief pause between batches to avoid rate limits
        if batch_start + chunk_size < len(documents):
            time.sleep(delay_between_chunks)

    return all_results

# Process 20 documents in batches of 8, 4 workers at a time:
large_document_set = [
    {"id": f"doc-{i}", "text": f"Content of document {i}."}
    for i in range(20)
]
results = fan_out_chunked(large_document_set, max_workers=4, chunk_size=8)
print(f"Processed: {len(results)} documents")
