import anthropic
import json
from concurrent.futures import ThreadPoolExecutor, as_completed

client = anthropic.Anthropic()

def map_extract_issues(code_file: str, filename: str) -> dict:
    """Map: extract issues from one code file."""
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=256,
        system=(
            "Review this code for bugs, security issues, and performance problems. "
            'Return JSON: {"filename": "...", "issues": [{"type": "...", "line": 0, "description": "..."}]}'
        ),
        messages=[{"role": "user", "content": f"File: {filename}\n\n{code_file}"}],
    )
    text = resp.content[0].text.strip()
    if text.startswith("```"):
        lines = text.split("\n")
        text = "\n".join(lines[1:-1] if lines[-1].strip() == "```" else lines[1:])
    try:
        return json.loads(text)
    except json.JSONDecodeError:
        return {"filename": filename, "issues": []}

def reduce_aggregate_report(all_file_issues: list[dict]) -> str:
    """Reduce: aggregate all file-level issues into a prioritized report."""
    total_issues = sum(len(f.get("issues", [])) for f in all_file_issues)
    issues_by_file = json.dumps(all_file_issues, indent=2)

    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=512,
        system=(
            "You are given code review results for multiple files. "
            "Produce a prioritized bug report: "
            "1) List the top 3 most critical issues across all files. "
            "2) Summarize the overall code health in one sentence."
        ),
        messages=[{
            "role": "user",
            "content": f"Total issues found: {total_issues}\n\n{issues_by_file}"
        }],
    )
    return resp.content[0].text.strip()

def map_reduce_code_review(files: dict[str, str]) -> str:
    """
    Map-reduce code review:
    Map: review each file in parallel
    Reduce: aggregate into a prioritized report
    """
    all_results = []
    with ThreadPoolExecutor(max_workers=min(4, len(files))) as pool:
        futures = {
            pool.submit(map_extract_issues, content, filename): filename
            for filename, content in files.items()
        }
        for future in as_completed(futures):
            try:
                all_results.append(future.result())
            except Exception as e:
                all_results.append({"filename": futures[future], "issues": [], "error": str(e)})

    return reduce_aggregate_report(all_results)

# Example:
codebase = {
    "auth.py": "def login(user, pwd):\n    query = f'SELECT * FROM users WHERE name={user}'\n    # SQL injection vulnerability",
    "utils.py": "def parse(data):\n    return eval(data)  # dangerous eval",
    "api.py": "def get_user(id):\n    return db.query(id)",
}
report = map_reduce_code_review(codebase)
print(report)
